from __future__ import annotations

import json
from dataclasses import dataclass
from urllib.parse import urlparse

from server.config import BaseConfig, get_app_config
from server.utils.logging import get_app_logger


@dataclass(frozen=True)
class StartupAlert:
    code: str
    message: str


def _is_blank(value: object) -> bool:
    return not str(value or "").strip()


def _secret_too_short(value: object, *, min_length: int = 32) -> bool:
    return len(str(value or "").encode("utf-8")) < min_length


def _is_production(cfg: BaseConfig) -> bool:
    return not bool(getattr(cfg, "IS_DEV", False)) and not bool(getattr(cfg, "TESTING", False))


def _host_is_local(url: str) -> bool:
    parsed = urlparse(url)
    host = (parsed.hostname or "").lower()
    return host in {"localhost", "127.0.0.1", "0.0.0.0", "::1"}


def _is_insecure_public_url(url: str) -> bool:
    parsed = urlparse(url)
    return parsed.scheme == "http" and not _host_is_local(url)


def _has_valid_game_server_credentials(raw: str) -> bool:
    if _is_blank(raw):
        return False

    try:
        parsed = json.loads(raw)
    except Exception:
        return False

    if not isinstance(parsed, dict) or not parsed:
        return False

    for entry in parsed.values():
        if not isinstance(entry, dict):
            continue
        if str(entry.get("signing_secret") or "").strip():
            return True
    return False


def collect_startup_alerts(cfg: BaseConfig, server_role: str) -> list[StartupAlert]:
    """Return non-fatal startup safety alerts for the supplied runtime config."""
    alerts: list[StartupAlert] = []
    role = server_role.strip().lower()
    is_production = _is_production(cfg)

    if _is_blank(cfg.SECRET_KEY) or _secret_too_short(cfg.SECRET_KEY):
        alerts.append(
            StartupAlert(
                code="secret-key-weak-or-missing",
                message="SECRET_KEY is missing or shorter than 32 bytes; signed application data is not safe.",
            )
        )

    if _is_blank(cfg.JWT_SECRET_KEY) or _secret_too_short(cfg.JWT_SECRET_KEY):
        alerts.append(
            StartupAlert(
                code="jwt-secret-key-weak-or-missing",
                message="JWT_SECRET_KEY is missing or shorter than 32 bytes; authentication tokens are not safe.",
            )
        )

    google_client_id_present = not _is_blank(cfg.GOOGLE_CLIENT_ID)
    google_client_secret_present = not _is_blank(cfg.GOOGLE_CLIENT_SECRET)
    if google_client_id_present != google_client_secret_present:
        alerts.append(
            StartupAlert(
                code="google-oauth-partial-config",
                message="Google OAuth is partially configured; set both GOOGLE_CLIENT_ID and GOOGLE_CLIENT_SECRET.",
            )
        )

    if role == "game" and (
        _is_blank(cfg.GAME_SERVER_SELF_ID) or _is_blank(cfg.GAME_SERVER_SELF_SIGNING_SECRET)
    ):
        alerts.append(
            StartupAlert(
                code="game-server-identity-missing",
                message=(
                    "Dedicated game server identity is incomplete; registry heartbeat will be disabled until "
                    "GAME_SERVER_SELF_ID and GAME_SERVER_SELF_SIGNING_SECRET are set."
                ),
            )
        )

    if not is_production:
        return alerts

    if not bool(cfg.JWT_COOKIE_SECURE):
        alerts.append(
            StartupAlert(
                code="jwt-cookie-secure-disabled",
                message="JWT_COOKIE_SECURE is disabled in production; browser auth cookies may be sent over HTTP.",
            )
        )

    if not bool(cfg.AUTH_REQUIRE_EMAIL_VERIFICATION):
        alerts.append(
            StartupAlert(
                code="email-verification-disabled",
                message="AUTH_REQUIRE_EMAIL_VERIFICATION is disabled in production.",
            )
        )

    if "*" in {origin.strip() for origin in cfg.CORS_ALLOWED_ORIGINS}:
        alerts.append(
            StartupAlert(
                code="cors-wildcard-origin",
                message="CORS_ALLOWED_ORIGINS contains '*' while credentials are enabled.",
            )
        )

    public_urls = {
        "BACKEND_PUBLIC_BASE_URL": cfg.BACKEND_PUBLIC_BASE_URL,
        "FRONTEND_PUBLIC_BASE_URL": cfg.FRONTEND_PUBLIC_BASE_URL,
        "GAME_WS_PUBLIC_BASE_URL": cfg.GAME_WS_PUBLIC_BASE_URL,
        "CHAT_WS_PUBLIC_BASE_URL": cfg.CHAT_WS_PUBLIC_BASE_URL,
    }
    for key, value in public_urls.items():
        if _host_is_local(value):
            alerts.append(
                StartupAlert(
                    code=f"{key.lower()}-local-production-url",
                    message=f"{key} points at a local host in production: {value}",
                )
            )
        elif _is_insecure_public_url(value):
            alerts.append(
                StartupAlert(
                    code=f"{key.lower()}-insecure-production-url",
                    message=f"{key} uses HTTP in production: {value}",
                )
            )

    if role == "main" and not _has_valid_game_server_credentials(cfg.GAME_SERVER_CREDENTIALS_JSON):
        alerts.append(
            StartupAlert(
                code="game-server-credentials-missing",
                message=(
                    "GAME_SERVER_CREDENTIALS_JSON is missing or invalid in production; dedicated game servers "
                    "will not be able to authenticate with the control plane."
                ),
            )
        )

    return alerts


def emit_startup_alerts(
    server_role: str,
    cfg: BaseConfig | None = None,
    logger=None,
) -> list[StartupAlert]:
    """Log startup safety alerts without preventing the process from starting."""
    startup_logger = logger or get_app_logger()

    try:
        runtime_cfg = cfg or get_app_config()
        alerts = collect_startup_alerts(runtime_cfg, server_role)
    except Exception as exc:
        startup_logger.warning(
            "[StartupSafety] Unable to evaluate startup safety alerts for role=%s: %s",
            server_role,
            exc,
        )
        return []

    for alert in alerts:
        startup_logger.warning("[StartupSafety] %s: %s", alert.code, alert.message)

    return alerts
